import{_ as e,o as t,c as r,ae as n}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Ads (non-SANs) FAQ","description":"","frontmatter":{"title":"Ads (non-SANs) FAQ","slug":"ads-non-sans-faq"},"headers":[],"relativePath":"marketer-hub/ads-non-sans-faq.md","filePath":"marketer-hub/ads-non-sans-faq.md"}'),i={name:"marketer-hub/ads-non-sans-faq.md"};function s(o,a,p,c,l,d){return t(),r("div",null,[...a[0]||(a[0]=[n('<p>The most frequently asked questions about ads.</p><details><summary>How do I reset my ad partner’s settings?</summary><p>There may be times when you need to reset a partner&#39;s settings; i.e. when a partner updates their postback templates or when perhaps you&#39;ve made a mistake during partner setup. Resetting a partner&#39;s settings allows you to re-enable the partner integration with the correct information to accurately measure and attribute conversion.</p><p>By resetting your partner settings, this will:</p><ul><li>Disable the ad partner</li><li>Clear out all of your saved credentials and Postbacks that are already setup</li><li>Return the ad partner to its basic configuration</li></ul><p>To reset your ad partner&#39;s settings:</p><ol><li>Find your partner on the <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer">Partner Management</a> page.</li><li>Click on the <strong>Account Settings</strong> tab for your partner.</li><li>Click the <strong>Reset All Settings</strong> button.</li></ol></details><details><summary>How do I sign up as a Branch partner to run campaigns for my advertisers?</summary><p>To sign up as a partner with Branch, use our <a href="https://branchmetrics.typeform.com/to/XXkMePO9" target="_blank" rel="noreferrer">Partner Management Form</a>.</p><p>Our Business Development team will reach out to you to take this forward and work with you to get you onboarded.</p></details><details><summary>Why can’t my Ad Partner access Branch?</summary><p>Enabling the Ad Partner Integration through <strong>Ads &gt; Partner Management</strong> tab on the Dashboard, does not provide the Ad Partner access to the Dashboard.</p><p>In order to grant the Ad Partner access to your dashboard, please follow the guide no how to <a href="./add-agency-to-your-account.html">Grant an Agency Access</a>.</p></details><details><summary>Does re-authenticating an Ad Partner disrupt/break the existing campaigns?</summary><p>The re-authentication process refreshes the API integration for the concerned partner and will reflect any changes being made (ex. adding new ad accounts, any changes for event mapping/attribution windows/timezones, etc). This process takes around 24 hours to complete before the populated information reflects any changes.</p><p>Your campaign information and associated information will NOT be lost in the process.</p></details><details><summary>Why does clicking on an Ad Link with macros/parameteres redirect to a Branch error page?</summary><p>Macros like {{campaign}} are seen on Ad Links. When these ad links are added as click trackers in the actual ad by the ad network they are filled in by the actual value by the Ad Network itself. Clicking on these Ad Links with macros will not work since certain browsers do not accept brackets {{--}}. You can replace the macro with a test value and click on the link.</p><p>Example:</p><p>Test Ad Link: <a href="https://branchster.app.link/1DPD90PV2cb?%243p=a_digital_turbine&amp;%24aaid=%5BAAID%5D&amp;~campaign=%5BCAMPAIGN_NAME%5D&amp;~campaign_id=%5BCAMPAIGN_ID%5D&amp;~click_id=%5BClickID%5D&amp;~secondary_publisher=%5BSITE_NAME%5D" target="_blank" rel="noreferrer">https://branchster.app.link/1DPD90PV2cb?%243p=a_digital_turbine&amp;%24aaid=[AAID]&amp;~campaign=[CAMPAIGN_NAME]&amp;~campaign_id=[CAMPAIGN_ID]&amp;~click_id=[ClickID]&amp;~secondary_publisher=[SITE_NAME]</a></p><p>Notice the macro looks a little different here, it depends on the Ad Network on what type of macros they support. But the above link can be converted to the following for testing purposes:</p><p><a href="https://branchster.app.link/1DPD90PV2cb?%243p=a_digital_turbine&amp;%24aaid=11111111-2222-3333-4444-55555555&amp;~campaign=test_campaign&amp;~campaign_id=1234&amp;~click_id=abcd123&amp;~secondary_publisher=test_secondary_publisher" target="_blank" rel="noreferrer">https://branchster.app.link/1DPD90PV2cb?%243p=a_digital_turbine&amp;%24aaid=11111111-2222-3333-4444-55555555&amp;~campaign=test_campaign&amp;~campaign_id=1234&amp;~click_id=abcd123&amp;~secondary_publisher=test_secondary_publisher</a></p><p>Clicking on the above link will not throw the error.</p><p>Moreover, certain macros on the Ad Link may result in different behavior depending on the value being used to test. When troubleshooting your Ad Link, sure that you are using valid test values for each macro. Macros in particular that are prone to causing errors due to format are IDs like aaid, idfa, etc.</p></details><details><summary>How can I add more macros to Ad Links?</summary><p>The macros added on the Ad Links are a way for the Ad Network to forward the data to Branch. Branch can add any macro to the ad link if the Ad Network can support filling in of those macros.</p><p>Example:</p><p>If the link today looks like: <a href="https://branchster.app.link/1DPD90PV2cb?%243p=a_digital_turbine&amp;%24aaid=%5BAAID%5D&amp;~campaign=%5BCAMPAIGN_NAME%5D&amp;~campaign_id=%5BCAMPAIGN_ID%5D&amp;~click_id=%5BClickID%5D&amp;~secondary_publisher=%5BSITE_NAME%5D" target="_blank" rel="noreferrer">https://branchster.app.link/1DPD90PV2cb?%243p=a_digital_turbine&amp;%24aaid=[AAID]&amp;~campaign=[CAMPAIGN_NAME]&amp;~campaign_id=[CAMPAIGN_ID]&amp;~click_id=[ClickID]&amp;~secondary_publisher=[SITE_NAME]</a></p><p>And, you or the Ad Network wants to add another macro for creative_name, you can map it to one of the existing analytics labels on Branch listed here. Then, the link would look like: <a href="https://branchster.app.link/1DPD90PV2cb?%243p=a_digital_turbine&amp;%24aaid=%5BAAID%5D&amp;~campaign=%5BCAMPAIGN_NAME%5D&amp;~campaign_id=%5BCAMPAIGN_ID%5D&amp;~click_id=%5BClickID%5D&amp;~secondary_publisher=%5BSITE_NAME%5D&amp;~creative_name=%5BCREATIVE_NAME%5D" target="_blank" rel="noreferrer">https://branchster.app.link/1DPD90PV2cb?%243p=a_digital_turbine&amp;%24aaid=[AAID]&amp;~campaign=[CAMPAIGN_NAME]&amp;~campaign_id=[CAMPAIGN_ID]&amp;~click_id=[ClickID]&amp;~secondary_publisher=[SITE_NAME]&amp;~creative_name=[CREATIVE_NAME]</a></p><p>[CREATIVE_NAME] is the macro that the Ad Network should send us and we can map it to one of the existing labels as mentioned above, but also map it to any custom parameter, such as:</p><p><a href="https://branchster.app.link/1DPD90PV2cb?%243p=a_digital_turbine&amp;%24aaid=%5BAAID%5D&amp;~campaign=%5BCAMPAIGN_NAME%5D&amp;~campaign_id=%5BCAMPAIGN_ID%5D&amp;~click_id=%5BClickID%5D&amp;~secondary_publisher=%5BSITE_NAME%5D&amp;creativename=%5BCREATIVE_NAME%5D" target="_blank" rel="noreferrer">https://branchster.app.link/1DPD90PV2cb?%243p=a_digital_turbine&amp;%24aaid=[AAID]&amp;~campaign=[CAMPAIGN_NAME]&amp;~campaign_id=[CAMPAIGN_ID]&amp;~click_id=[ClickID]&amp;~secondary_publisher=[SITE_NAME]&amp;creativename=[CREATIVE_NAME]</a></p></details><details><summary>Why are the ads macros/parameters not visible in Branch?</summary><p>The analytics labels that can be viewed on the dashboard are listed <a href="https://help.branch.io/v1/docs/creating-a-deep-link" target="_blank" rel="noreferrer">here</a>. Any other custom macros that are added on the Ad Links will be visible in the exports via <a href="https://help.branch.io/v1-api/apidocs/daily-exports-api" target="_blank" rel="noreferrer">Daily Export API</a> or <a href="https://help.branch.io/v1-api/apidocs/custom-exports-api" target="_blank" rel="noreferrer">Custom Exports API</a> in the <code>last_attributed_touch_data_custom_fields</code> column.</p></details>',8)])])}const u=e(i,[["render",s]]);export{h as __pageData,u as default};
